PRAGMA foreign_keys = OFF;
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:30', 39, 30, 23, 461, 4088, 'اِنَّكَ مَيِّتٌ وَّاِنَّهُمْ مَّيِّتُوْنَ ۖ', 'Sesungguhnya engkau (Nabi Muhammad akan) mati dan sesungguhnya mereka pun (akan) mati.', '', 'https://everyayah.com/data/Alafasy_128kbps/039030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:31', 39, 31, 23, 461, 4089, 'ثُمَّ اِنَّكُمْ يَوْمَ الْقِيٰمَةِ عِنْدَ رَبِّكُمْ تَخْتَصِمُوْنَ ࣖ   ۔', 'Kemudian, sesungguhnya kamu sekalian pada hari Kiamat akan berbantah-bantahan di hadapan Tuhanmu.', '', 'https://everyayah.com/data/Alafasy_128kbps/039031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:32', 39, 32, 24, 462, 4090, '۞ فَمَنْ اَظْلَمُ مِمَّنْ كَذَبَ عَلَى اللّٰهِ وَكَذَّبَ بِالصِّدْقِ اِذْ جَاۤءَهٗۗ  اَلَيْسَ فِيْ جَهَنَّمَ مَثْوًى لِّلْكٰفِرِيْنَ ', 'Maka, siapakah yang lebih zalim daripada orang yang membuat kebohongan terhadap Allah dan mendustakan kebenaran ketika datang kepadanya? Bukankah di (neraka) Jahanam terdapat tempat tinggal bagi orang-orang kafir?', '', 'https://everyayah.com/data/Alafasy_128kbps/039032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:33', 39, 33, 24, 462, 4091, 'وَالَّذِيْ جَاۤءَ بِالصِّدْقِ وَصَدَّقَ بِهٖٓ اُولٰۤىِٕكَ هُمُ الْمُتَّقُوْنَ', 'Orang yang membawa kebenaran (Nabi Muhammad) dan yang membenarkannya, mereka itulah orang-orang yang bertakwa.', '', 'https://everyayah.com/data/Alafasy_128kbps/039033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:34', 39, 34, 24, 462, 4092, 'لَهُمْ مَّا يَشَاۤءُوْنَ عِنْدَ رَبِّهِمْ ۗ ذٰلِكَ جَزَاۤءُ الْمُحْسِنِيْنَۚ', 'Mereka memperoleh apa yang mereka kehendaki di sisi Tuhannya. Itulah balasan bagi orang-orang yang berbuat kebaikan.', '', 'https://everyayah.com/data/Alafasy_128kbps/039034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:35', 39, 35, 24, 462, 4093, 'لِيُكَفِّرَ اللّٰهُ عَنْهُمْ اَسْوَاَ الَّذِيْ عَمِلُوْا وَيَجْزِيَهُمْ اَجْرَهُمْ بِاَحْسَنِ الَّذِيْ كَانُوْا يَعْمَلُوْنَ', '(Demikian itu) agar Allah menghapus (dosa) perbuatan mereka yang paling buruk yang pernah mereka lakukan dan memberi pahala kepada mereka dengan yang lebih baik daripada apa yang dahulu mereka kerjakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/039035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:36', 39, 36, 24, 462, 4094, 'اَلَيْسَ اللّٰهُ بِكَافٍ عَبْدَهٗۗ وَيُخَوِّفُوْنَكَ بِالَّذِيْنَ مِنْ دُوْنِهٖۗ وَمَنْ يُّضْلِلِ اللّٰهُ فَمَا لَهٗ مِنْ هَادٍۚ', 'Bukankah Allah yang mencukupi hamba-Nya? Mereka menakut-nakutimu dengan (sesembahan) selain Dia. Siapa yang Allah biarkan sesat tidak ada satu pun yang memberi petunjuk kepadanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/039036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:37', 39, 37, 24, 462, 4095, 'وَمَنْ يَّهْدِ اللّٰهُ فَمَا لَهٗ مِنْ مُّضِلٍّ ۗ اَلَيْسَ اللّٰهُ بِعَزِيْزٍ ذِى انْتِقَامٍ', 'Siapa yang Allah tunjuki tidak satu pun yang menyesatkannya. Bukankah Allah Maha Perkasa lagi Maha Memiliki (kekuasaan) untuk membalas?', '', 'https://everyayah.com/data/Alafasy_128kbps/039037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:38', 39, 38, 24, 462, 4096, 'وَلَىِٕنْ سَاَلْتَهُمْ مَّنْ خَلَقَ السَّمٰوٰتِ وَالْاَرْضَ لَيَقُوْلُنَّ اللّٰهُ ۗ قُلْ اَفَرَءَيْتُمْ مَّا تَدْعُوْنَ مِنْ دُوْنِ اللّٰهِ اِنْ اَرَادَنِيَ اللّٰهُ بِضُرٍّ هَلْ هُنَّ كٰشِفٰتُ ضُرِّهٖٓ اَوْ اَرَادَنِيْ بِرَحْمَةٍ هَلْ هُنَّ مُمْسِكٰتُ رَحْمَتِهٖۗ قُلْ حَسْبِيَ اللّٰهُ ۗعَلَيْهِ يَتَوَكَّلُ الْمُتَوَكِّلُوْنَ ', 'Sungguh, jika engkau (Nabi Muhammad) bertanya kepada mereka (kaum musyrik Makkah) siapa yang menciptakan langit dan bumi, niscaya mereka menjawab, “Allah.” Katakanlah, “Kalau begitu, tahukah kamu tentang apa yang kamu sembah selain Allah jika Allah hendak mendatangkan bencana kepadaku, apakah mereka (sesembahan itu) mampu menghilangkan bencana itu atau jika Allah hendak memberi rahmat kepadaku, apakah mereka dapat mencegah rahmat-Nya?” Katakanlah, “Cukuplah Allah (sebagai pelindung) bagiku. Hanya kepada-Nya orang-orang yang bertawakal berserah diri.”', '', 'https://everyayah.com/data/Alafasy_128kbps/039038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:39', 39, 39, 24, 462, 4097, 'قُلْ يٰقَوْمِ اعْمَلُوْا عَلٰى مَكَانَتِكُمْ اِنِّيْ عَامِلٌ ۚفَسَوْفَ تَعْلَمُوْنَۙ', 'Katakanlah, “Wahai kaumku, berbuatlah menurut kedudukanmu! Sesungguhnya aku pun berbuat (demikian). Kelak kamu akan mengetahui', '', 'https://everyayah.com/data/Alafasy_128kbps/039039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:40', 39, 40, 24, 462, 4098, 'مَنْ يَّأْتِيْهِ عَذَابٌ يُّخْزِيْهِ وَيَحِلُّ عَلَيْهِ عَذَابٌ مُّقِيْمٌ', 'siapa yang akan mendapat siksa yang menghinakannya dan yang akan ditimpa azab yang kekal.”', '', 'https://everyayah.com/data/Alafasy_128kbps/039040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:41', 39, 41, 24, 463, 4099, 'اِنَّآ اَنْزَلْنَا عَلَيْكَ الْكِتٰبَ لِلنَّاسِ بِالْحَقِّۚ فَمَنِ اهْتَدٰى فَلِنَفْسِهٖۚ وَمَنْ ضَلَّ فَاِنَّمَا يَضِلُّ عَلَيْهَا ۚوَمَآ اَنْتَ عَلَيْهِمْ بِوَكِيْلٍ ࣖ', 'Sesungguhnya Kami telah menurunkan kepadamu (Nabi Muhammad) Kitab (Al-Qur’an) untuk (seluruh) manusia dengan hak. Siapa yang mendapat petunjuk, (petunjuk itu) untuk dirinya sendiri, dan siapa yang sesat, sesungguhnya kesesatan itu untuk dirinya sendiri. Engkau bukanlah penanggung jawab mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/039041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:42', 39, 42, 24, 463, 4100, 'اَللّٰهُ يَتَوَفَّى الْاَنْفُسَ حِيْنَ مَوْتِهَا وَالَّتِيْ لَمْ تَمُتْ فِيْ مَنَامِهَا ۚ فَيُمْسِكُ الَّتِيْ قَضٰى عَلَيْهَا الْمَوْتَ وَيُرْسِلُ الْاُخْرٰىٓ اِلٰٓى اَجَلٍ مُّسَمًّىۗ اِنَّ فِيْ ذٰلِكَ لَاٰيٰتٍ لِّقَوْمٍ يَّتَفَكَّرُوْنَ', 'Allah menggenggam nyawa (manusia) pada saat kematiannya dan yang belum mati ketika dia tidur. Dia menahan nyawa yang telah Dia tetapkan kematiannya dan Dia melepaskan nyawa yang lain sampai waktu yang ditentukan. Sesungguhnya pada yang demikian itu benar-benar terdapat bukti-bukti (kekuasaan) Allah bagi kaum yang berpikir.', '', 'https://everyayah.com/data/Alafasy_128kbps/039042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:43', 39, 43, 24, 463, 4101, 'اَمِ اتَّخَذُوْا مِنْ دُوْنِ اللّٰهِ شُفَعَاۤءَۗ قُلْ اَوَلَوْ كَانُوْا لَا يَمْلِكُوْنَ شَيْـًٔا وَّلَا يَعْقِلُوْنَ ', 'Apakah mereka juga menjadikan penolong selain Allah? Katakanlah, “Apakah (kamu menjadikannya penolong juga) meskipun mereka tidak memiliki suatu apa pun dan tidak mengerti?”', '', 'https://everyayah.com/data/Alafasy_128kbps/039043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:44', 39, 44, 24, 463, 4102, 'قُلْ لِّلّٰهِ الشَّفَاعَةُ جَمِيْعًا ۗ لَهٗ مُلْكُ السَّمٰوٰتِ وَالْاَرْضِۗ ثُمَّ اِلَيْهِ تُرْجَعُوْنَ', 'Katakanlah (Nabi Muhammad), “Hanya milik Allah pertolongan itu semuanya. Milik-Nya kerajaan langit dan bumi. Kemudian, hanya kepada-Nya kamu dikembalikan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/039044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:45', 39, 45, 24, 463, 4103, 'وَاِذَا ذُكِرَ اللّٰهُ وَحْدَهُ اشْمَـَٔزَّتْ قُلُوْبُ الَّذِيْنَ لَا يُؤْمِنُوْنَ بِالْاٰخِرَةِۚ وَاِذَا ذُكِرَ الَّذِيْنَ مِنْ دُوْنِهٖٓ اِذَا هُمْ يَسْتَبْشِرُوْنَ', 'Apabila hanya (nama) Allah yang disebut, hati orang-orang yang tidak beriman kepada akhirat kesal. Namun, apabila (nama-nama sembahan) selain Allah disebut, tiba-tiba mereka bergembira.', '', 'https://everyayah.com/data/Alafasy_128kbps/039045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:46', 39, 46, 24, 463, 4104, 'قُلِ اللّٰهُمَّ فَاطِرَ السَّمٰوٰتِ وَالْاَرْضِ عٰلِمَ الْغَيْبِ وَالشَّهَادَةِ اَنْتَ تَحْكُمُ بَيْنَ عِبَادِكَ فِيْ مَا كَانُوْا فِيْهِ يَخْتَلِفُوْنَ', 'Katakanlah, “Ya Allah, Pencipta langit dan bumi, yang mengetahui segala yang gaib dan nyata, Engkaulah yang memutuskan di antara hamba-hamba-Mu apa yang selalu mereka perselisihkan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/039046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:47', 39, 47, 24, 463, 4105, 'وَلَوْ اَنَّ لِلَّذِيْنَ ظَلَمُوْا مَا فِى الْاَرْضِ جَمِيْعًا وَّمِثْلَهٗ مَعَهٗ لَافْتَدَوْا بِهٖ مِنْ سُوْۤءِ الْعَذَابِ يَوْمَ الْقِيٰمَةِۗ وَبَدَا لَهُمْ مِّنَ اللّٰهِ مَا لَمْ يَكُوْنُوْا يَحْتَسِبُوْنَ', 'Sekiranya orang-orang yang zalim mempunyai segala apa yang ada di bumi dan ditambah lagi sebanyak itu, niscaya mereka akan menebus dirinya dengan itu dari azab yang buruk pada hari Kiamat. Tampak jelaslah bagi mereka (azab) dari Allah yang belum pernah mereka perkirakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/039047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:48', 39, 48, 24, 464, 4106, 'وَبَدَا لَهُمْ سَيِّاٰتُ مَا كَسَبُوْا وَحَاقَ بِهِمْ مَّا كَانُوْا بِهٖ يَسْتَهْزِءُوْنَ', 'Tampak jelaslah bagi mereka keburukan-keburukan yang mereka kerjakan (di dunia) dan mereka diliputi oleh (azab) yang selalu mereka olok-olokkan.', '', 'https://everyayah.com/data/Alafasy_128kbps/039048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:49', 39, 49, 24, 464, 4107, 'فَاِذَا مَسَّ الْاِنْسَانَ ضُرٌّ دَعَانَاۖ  ثُمَّ اِذَا خَوَّلْنٰهُ نِعْمَةً مِّنَّاۙ قَالَ اِنَّمَآ اُوْتِيْتُهٗ عَلٰى عِلْمٍ ۗبَلْ هِيَ فِتْنَةٌ وَّلٰكِنَّ اَكْثَرَهُمْ لَا يَعْلَمُوْنَ', 'Apabila ditimpa bencana, manusia menyeru Kami. Kemudian, apabila Kami memberikan nikmat sebagai anugerah Kami kepadanya, dia berkata, “Sesungguhnya aku diberikan (nikmat) itu hanyalah karena kepintaranku.” Sebenarnya, itu adalah ujian, tetapi kebanyakan mereka tidak mengetahui(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/039049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:50', 39, 50, 24, 464, 4108, 'قَدْ قَالَهَا الَّذِيْنَ مِنْ قَبْلِهِمْ فَمَآ اَغْنٰى عَنْهُمْ مَّا كَانُوْا يَكْسِبُوْنَ', 'Sungguh, orang-orang yang sebelum mereka pun telah mengatakan hal itu. Maka, tidak berguna lagi bagi mereka apa yang selalu mereka usahakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/039050.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:51', 39, 51, 24, 464, 4109, 'فَاَصَابَهُمْ سَيِّاٰتُ مَا كَسَبُوْا ۗوَالَّذِيْنَ ظَلَمُوْا مِنْ هٰٓؤُلَاۤءِ سَيُصِيْبُهُمْ سَيِّاٰتُ مَا كَسَبُوْا ۙوَمَا هُمْ بِمُعْجِزِيْنَ', 'Lalu, mereka ditimpa (bencana akibat) keburukan-keburukan yang mereka perbuat. Orang-orang yang zalim di antara mereka juga akan ditimpa (bencana akibat) keburukan-keburukan yang mereka perbuat dan tidak dapat melepaskan diri (darinya).', '', 'https://everyayah.com/data/Alafasy_128kbps/039051.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:52', 39, 52, 24, 464, 4110, 'اَوَلَمْ يَعْلَمُوْٓا اَنَّ اللّٰهَ يَبْسُطُ الرِّزْقَ لِمَنْ يَّشَاۤءُ وَيَقْدِرُ ۗاِنَّ فِيْ ذٰلِكَ لَاٰيٰتٍ لِّقَوْمٍ يُّؤْمِنُوْنَ ࣖ', 'Tidakkah mereka mengetahui bahwa Allah melapangkan rezeki bagi siapa yang Dia kehendaki dan menyempitkannya (bagi siapa yang Dia kehendaki)? Sesungguhnya pada yang demikian itu benar-benar terdapat tanda-tanda (kekuasaan Allah) bagi kaum yang beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/039052.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:53', 39, 53, 24, 464, 4111, '۞ قُلْ يٰعِبَادِيَ الَّذِيْنَ اَسْرَفُوْا عَلٰٓى اَنْفُسِهِمْ لَا تَقْنَطُوْا مِنْ رَّحْمَةِ اللّٰهِ ۗاِنَّ اللّٰهَ يَغْفِرُ الذُّنُوْبَ جَمِيْعًا ۗاِنَّهٗ هُوَ الْغَفُوْرُ الرَّحِيْمُ', 'Katakanlah (Nabi Muhammad), “Wahai hamba-hamba-Ku yang melampaui batas (dengan menzalimi) dirinya sendiri, janganlah berputus asa dari rahmat Allah. Sesungguhnya Allah mengampuni dosa semuanya.663) Sesungguhnya Dialah Yang Maha Pengampun lagi Maha Penyayang.', '663) Semua dosa bisa diampuni Allah Swt., kecuali dosa syirik (lihat surah an-Nisā’ [4]: 48).', 'https://everyayah.com/data/Alafasy_128kbps/039053.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:54', 39, 54, 24, 464, 4112, 'وَاَنِيْبُوْٓا اِلٰى رَبِّكُمْ وَاَسْلِمُوْا لَهٗ مِنْ قَبْلِ اَنْ يَّأْتِيَكُمُ الْعَذَابُ ثُمَّ لَا تُنْصَرُوْنَ', 'Kembalilah kepada Tuhanmu dan berserahdirilah kepada-Nya sebelum datang azab kepadamu, kemudian kamu tidak akan ditolong.', '', 'https://everyayah.com/data/Alafasy_128kbps/039054.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:55', 39, 55, 24, 464, 4113, 'وَاتَّبِعُوْٓا اَحْسَنَ مَآ اُنْزِلَ اِلَيْكُمْ مِّنْ رَّبِّكُمْ مِّنْ قَبْلِ اَنْ يَّأْتِيَكُمُ الْعَذَابُ بَغْتَةً وَّاَنْتُمْ لَا تَشْعُرُوْنَ ۙ  ', 'Ikutilah sebaik-baik apa yang diturunkan kepadamu dari Tuhanmu (Al-Qur’an) sebelum azab datang kepadamu secara mendadak, sedangkan kamu tidak menyadarinya.', '', 'https://everyayah.com/data/Alafasy_128kbps/039055.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:56', 39, 56, 24, 464, 4114, 'اَنْ تَقُوْلَ نَفْسٌ يّٰحَسْرَتٰى عَلٰى مَا فَرَّطْتُّ فِيْ جَنْۢبِ اللّٰهِ وَاِنْ كُنْتُ لَمِنَ السّٰخِرِيْنَۙ   ', '(Maksudnya,) supaya (tidak) ada orang yang berkata, “Alangkah besar penyesalanku atas kelalaianku dalam (menunaikan kewajiban) terhadap Allah dan sesungguhnya aku benar-benar termasuk orang-orang yang memperolok-olokkan (agama Allah).”', '', 'https://everyayah.com/data/Alafasy_128kbps/039056.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:57', 39, 57, 24, 465, 4115, 'اَوْ تَقُوْلَ لَوْ اَنَّ اللّٰهَ هَدٰىنِيْ لَكُنْتُ مِنَ الْمُتَّقِيْنَ ۙ', 'Atau, supaya (tidak) ada yang berkata, “Seandainya Allah memberi petunjuk kepadaku, tentulah aku termasuk orang-orang yang bertakwa.”', '', 'https://everyayah.com/data/Alafasy_128kbps/039057.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:58', 39, 58, 24, 465, 4116, 'اَوْ تَقُوْلَ حِيْنَ تَرَى الْعَذَابَ لَوْ اَنَّ لِيْ كَرَّةً فَاَكُوْنَ مِنَ الْمُحْسِنِيْنَ', 'Atau, supaya (tidak) ada (pula) yang berkata ketika melihat azab, “Seandainya aku dapat kembali (ke dunia), tentu aku termasuk orang-orang yang muhsin.”', '', 'https://everyayah.com/data/Alafasy_128kbps/039058.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:59', 39, 59, 24, 465, 4117, 'بَلٰى قَدْ جَاۤءَتْكَ اٰيٰتِيْ فَكَذَّبْتَ بِهَا وَاسْتَكْبَرْتَ وَكُنْتَ مِنَ الْكٰفِرِيْنَ', 'Tidak begitu! Sebenarnya ayat-ayat-Ku telah datang kepadamu, tetapi kamu mendustakannya, menyombongkan diri, dan termasuk orang-orang kafir.', '', 'https://everyayah.com/data/Alafasy_128kbps/039059.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:60', 39, 60, 24, 465, 4118, 'وَيَوْمَ الْقِيٰمَةِ تَرَى الَّذِيْنَ كَذَبُوْا عَلَى اللّٰهِ وُجُوْهُهُمْ مُّسْوَدَّةٌ  ۗ اَلَيْسَ فِيْ جَهَنَّمَ مَثْوًى لِّلْمُتَكَبِّرِيْنَ', 'Pada hari Kiamat, engkau akan melihat bahwa orang-orang yang berdusta kepada Allah wajahnya menghitam. Bukankah (neraka) Jahanam itu tempat tinggal bagi orang-orang yang takabur?', '', 'https://everyayah.com/data/Alafasy_128kbps/039060.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:61', 39, 61, 24, 465, 4119, 'وَيُنَجِّى اللّٰهُ الَّذِيْنَ اتَّقَوْا بِمَفَازَتِهِمْۖ  لَا يَمَسُّهُمُ السُّوْۤءُ وَلَا هُمْ يَحْزَنُوْنَ', 'Allah menyelamatkan orang-orang yang bertakwa karena kemenangannya sehingga mereka tidak disentuh oleh azab dan tidak bersedih.', '', 'https://everyayah.com/data/Alafasy_128kbps/039061.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:62', 39, 62, 24, 465, 4120, 'اَللّٰهُ خَالِقُ كُلِّ شَيْءٍ ۙوَّهُوَ عَلٰى كُلِّ شَيْءٍ وَّكِيْلٌ', 'Allah adalah pencipta segala sesuatu dan Dia Maha Pemelihara atas segala sesuatu.', '', 'https://everyayah.com/data/Alafasy_128kbps/039062.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:63', 39, 63, 24, 465, 4121, 'لَهٗ مَقَالِيْدُ السَّمٰوٰتِ وَالْاَرْضِۗ وَالَّذِيْنَ كَفَرُوْا بِاٰيٰتِ اللّٰهِ اُولٰۤىِٕكَ هُمُ الْخٰسِرُوْنَ ࣖ ', 'Milik-Nyalah kunci-kunci (perbendaharaan) langit dan bumi. Orang-orang yang kufur terhadap ayat-ayat Allah, mereka itulah orang-orang yang rugi.', '', 'https://everyayah.com/data/Alafasy_128kbps/039063.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:64', 39, 64, 24, 465, 4122, 'قُلْ اَفَغَيْرَ اللّٰهِ تَأْمُرُوْۤنِّيْٓ اَعْبُدُ اَيُّهَا الْجٰهِلُوْنَ', 'Katakanlah (Nabi Muhammad), “Apakah kamu menyuruhku (untuk) menyembah selain Allah, wahai orang-orang yang bodoh?”', '', 'https://everyayah.com/data/Alafasy_128kbps/039064.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:65', 39, 65, 24, 465, 4123, 'وَلَقَدْ اُوْحِيَ اِلَيْكَ وَاِلَى الَّذِيْنَ مِنْ قَبْلِكَۚ  لَىِٕنْ اَشْرَكْتَ لَيَحْبَطَنَّ عَمَلُكَ وَلَتَكُوْنَنَّ مِنَ الْخٰسِرِيْنَ', 'Sungguh, benar-benar telah diwahyukan kepadamu dan kepada orang-orang (para nabi) sebelummu, “Sungguh, jika engkau mempersekutukan (Allah), niscaya akan gugurlah amalmu dan tentulah engkau termasuk orang-orang yang rugi.', '', 'https://everyayah.com/data/Alafasy_128kbps/039065.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:66', 39, 66, 24, 465, 4124, 'بَلِ اللّٰهَ فَاعْبُدْ وَكُنْ مِّنَ الشّٰكِرِيْنَ', 'Oleh karena itu, sembahlah Allah (saja) dan jadilah engkau termasuk orang-orang yang bersyukur.”', '', 'https://everyayah.com/data/Alafasy_128kbps/039066.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:67', 39, 67, 24, 465, 4125, 'وَمَا قَدَرُوا اللّٰهَ حَقَّ قَدْرِهٖۖ وَالْاَرْضُ جَمِيْعًا قَبْضَتُهٗ يَوْمَ الْقِيٰمَةِ وَالسَّمٰوٰتُ مَطْوِيّٰتٌۢ بِيَمِيْنِهٖ ۗسُبْحٰنَهٗ وَتَعٰلٰى عَمَّا يُشْرِكُوْنَ', 'Mereka tidak mengagungkan Allah sebagaimana mestinya. Padahal, bumi seluruhnya (ada dalam) genggaman-Nya pada hari Kiamat dan langit digulung dengan tangan kanan-Nya.664) Maha Suci dan Maha Tinggi Dia dari apa yang mereka persekutukan.', '664) Ayat ini menggambarkan kebesaran dan kekuasaan Allah Swt. dan hanya Dia yang berkuasa pada hari Kiamat.', 'https://everyayah.com/data/Alafasy_128kbps/039067.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:68', 39, 68, 24, 466, 4126, 'وَنُفِخَ فِى الصُّوْرِ فَصَعِقَ مَنْ فِى السَّمٰوٰتِ وَمَنْ فِى الْاَرْضِ اِلَّا مَنْ شَاۤءَ اللّٰهُ ۗ ثُمَّ نُفِخَ فِيْهِ اُخْرٰى فَاِذَا هُمْ قِيَامٌ يَّنْظُرُوْنَ', 'Sangkakala pun ditiup sehingga matilah semua (makhluk) yang (ada) di langit dan di bumi, kecuali mereka yang dikehendaki Allah. Kemudian, ia ditiup sekali lagi. Seketika itu, mereka bangun (dari kuburnya dan) menunggu (keputusan Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/039068.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:69', 39, 69, 24, 466, 4127, 'وَاَشْرَقَتِ الْاَرْضُ بِنُوْرِ رَبِّهَا وَوُضِعَ الْكِتٰبُ وَجِايْۤءَ بِالنَّبِيّٖنَ وَالشُّهَدَاۤءِ وَقُضِيَ بَيْنَهُمْ بِالْحَقِّ وَهُمْ لَا يُظْلَمُوْنَ', 'Bumi (padang Mahsyar) menjadi terang benderang dengan cahaya Tuhannya, buku (catatan amal) diberikan (kepada setiap orang), para nabi dan para saksi pun dihadirkan, lalu diberikan keputusan di antara mereka secara adil dan mereka tidak dizalimi.', '', 'https://everyayah.com/data/Alafasy_128kbps/039069.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:70', 39, 70, 24, 466, 4128, 'وَوُفِّيَتْ كُلُّ نَفْسٍ مَّا عَمِلَتْ وَهُوَ اَعْلَمُ بِمَا يَفْعَلُوْنَ ࣖ ', 'Setiap jiwa diberi balasan dengan sempurna sesuai dengan apa yang telah dikerjakannya dan Dia paling tahu tentang apa yang mereka lakukan.', '', 'https://everyayah.com/data/Alafasy_128kbps/039070.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:71', 39, 71, 24, 466, 4129, 'وَسِيْقَ الَّذِيْنَ كَفَرُوْٓا اِلٰى جَهَنَّمَ زُمَرًا ۗحَتّٰىٓ اِذَا جَاۤءُوْهَا فُتِحَتْ اَبْوَابُهَا وَقَالَ لَهُمْ خَزَنَتُهَآ اَلَمْ يَأْتِكُمْ رُسُلٌ مِّنْكُمْ يَتْلُوْنَ عَلَيْكُمْ اٰيٰتِ رَبِّكُمْ وَيُنْذِرُوْنَكُمْ لِقَاۤءَ يَوْمِكُمْ هٰذَا ۗقَالُوْا بَلٰى وَلٰكِنْ حَقَّتْ كَلِمَةُ الْعَذَابِ عَلَى الْكٰفِرِيْنَ', 'Orang-orang yang kufur digiring ke (neraka) Jahanam secara berombongan sehingga apabila mereka telah sampai di sana, pintu-pintunya dibuka dan para penjaganya berkata kepada mereka, “Apakah belum pernah datang kepadamu rasul-rasul dari kalanganmu yang membacakan ayat-ayat Tuhanmu dan memperingatkan kepadamu pertemuan (dengan) harimu ini?” Mereka menjawab, “Benar, (telah datang para rasul).” Akan tetapi, ketetapan azab pasti berlaku terhadap orang-orang kafir.', '', 'https://everyayah.com/data/Alafasy_128kbps/039071.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:72', 39, 72, 24, 466, 4130, 'قِيْلَ ادْخُلُوْٓا اَبْوَابَ جَهَنَّمَ خٰلِدِيْنَ فِيْهَا ۚفَبِئْسَ مَثْوَى الْمُتَكَبِّرِيْنَ', 'Dikatakan (kepada mereka), “Masuklah pintu-pintu (neraka) Jahanam (untuk tinggal) di dalamnya selama-lamanya!” Maka, (neraka Jahanam) itu seburuk-buruk tempat tinggal bagi orang-orang yang takabur.', '', 'https://everyayah.com/data/Alafasy_128kbps/039072.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:73', 39, 73, 24, 466, 4131, 'وَسِيْقَ الَّذِيْنَ اتَّقَوْا رَبَّهُمْ اِلَى الْجَنَّةِ زُمَرًا ۗحَتّٰىٓ اِذَا جَاۤءُوْهَا وَفُتِحَتْ اَبْوَابُهَا وَقَالَ لَهُمْ خَزَنَتُهَا سَلٰمٌ عَلَيْكُمْ طِبْتُمْ فَادْخُلُوْهَا خٰلِدِيْنَ', 'Orang-orang yang bertakwa kepada Tuhannya diantar ke dalam surga secara berombongan sehingga apabila mereka telah sampai di sana dan pintu-pintunya telah dibuka, para penjaganya berkata kepada mereka, “Salāmun ‘alaikum (semoga keselamatan tercurah kepadamu), berbahagialah kamu. Maka, masuklah ke dalamnya (untuk tinggal) selama-lamanya!”', '', 'https://everyayah.com/data/Alafasy_128kbps/039073.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:74', 39, 74, 24, 466, 4132, 'وَقَالُوا الْحَمْدُ لِلّٰهِ الَّذِيْ صَدَقَنَا وَعْدَهٗ وَاَوْرَثَنَا الْاَرْضَ نَتَبَوَّاُ مِنَ الْجَنَّةِ حَيْثُ نَشَاۤءُ ۚفَنِعْمَ اَجْرُ الْعٰمِلِيْنَ', 'Mereka berkata, “Segala puji bagi Allah yang telah memenuhi janji-Nya dan mewariskan bumi (di akhirat) ini kepada kami sehingga dapat menempati surga sesuai dengan kehendak kami.” (Surga adalah) sebaik-baik balasan bagi orang-orang yang beramal (saleh).', '', 'https://everyayah.com/data/Alafasy_128kbps/039074.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('39:75', 39, 75, 24, 467, 4133, 'وَتَرَى الْمَلٰۤىِٕكَةَ حَاۤفِّيْنَ مِنْ حَوْلِ الْعَرْشِ يُسَبِّحُوْنَ بِحَمْدِ رَبِّهِمْۚ وَقُضِيَ بَيْنَهُمْ بِالْحَقِّ وَقِيْلَ الْحَمْدُ لِلّٰهِ رَبِّ الْعٰلَمِيْنَ ࣖ', 'Engkau (Nabi Muhammad) akan melihat malaikat melingkar di sekeliling ʻArasy. Mereka bertasbih sambil memuji Tuhannya. (Urusan) di antara mereka (seluruh makhluk) diputuskan dengan hak (adil). (Ketika itu) dikatakan, “Segala puji bagi Allah, Tuhan semesta alam.”', '', 'https://everyayah.com/data/Alafasy_128kbps/039075.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:1', 40, 1, 24, 467, 4134, ' حٰمۤ  ۚ ', 'Ḥā Mīm.', '', 'https://everyayah.com/data/Alafasy_128kbps/040001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:2', 40, 2, 24, 467, 4135, 'تَنْزِيْلُ الْكِتٰبِ مِنَ اللّٰهِ الْعَزِيْزِ الْعَلِيْمِۙ', 'Diturunkannya Kitab (Al-Qur’an) ini dari Allah Yang Maha Perkasa lagi Maha Mengetahui.', '', 'https://everyayah.com/data/Alafasy_128kbps/040002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:3', 40, 3, 24, 467, 4136, 'غَافِرِ الذَّنْۢبِ وَقَابِلِ التَّوْبِ شَدِيْدِ الْعِقَابِ ذِى الطَّوْلِۗ  لَآ اِلٰهَ اِلَّا هُوَ ۗاِلَيْهِ الْمَصِيْرُ ', '(Dia) Pengampun dosa, Penerima tobat, Pemberi hukuman yang keras, (dan) Pemilik karunia. Tidak ada tuhan  selain Dia. Hanya kepada-Nyalah (semua makhluk) kembali.', '', 'https://everyayah.com/data/Alafasy_128kbps/040003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:4', 40, 4, 24, 467, 4137, 'مَا يُجَادِلُ فِيْٓ اٰيٰتِ اللّٰهِ اِلَّا الَّذِيْنَ كَفَرُوْا فَلَا يَغْرُرْكَ تَقَلُّبُهُمْ فِى الْبِلَادِ', 'Tidak ada yang memperdebatkan ayat-ayat Allah, kecuali orang-orang yang kufur. Oleh karena itu, janganlah engkau (Nabi Muhammad) tertipu oleh bolak-balik perjalanan mereka di seluruh negeri.', '', 'https://everyayah.com/data/Alafasy_128kbps/040004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:5', 40, 5, 24, 467, 4138, 'كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوْحٍ وَّالْاَحْزَابُ مِنْۢ بَعْدِهِمْ ۖوَهَمَّتْ كُلُّ اُمَّةٍۢ بِرَسُوْلِهِمْ لِيَأْخُذُوْهُ وَجَادَلُوْا بِالْبَاطِلِ لِيُدْحِضُوْا بِهِ الْحَقَّ فَاَخَذْتُهُمْ ۗفَكَيْفَ كَانَ عِقَابِ', 'Sebelum mereka, kaum Nuh dan golongan-golongan yang bersekutu setelah mereka mendustakan (rasul). Setiap umat telah merencanakan (tipu daya) terhadap rasul mereka untuk membunuhnya. Mereka membantah dengan (alasan) yang batil untuk melenyapkan kebenaran. Maka, Aku menyiksa mereka. Bagaimanakah (pedihnya) azab-Ku?', '', 'https://everyayah.com/data/Alafasy_128kbps/040005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:6', 40, 6, 24, 467, 4139, 'وَكَذٰلِكَ حَقَّتْ كَلِمَتُ رَبِّكَ عَلَى الَّذِيْنَ كَفَرُوْٓا اَنَّهُمْ اَصْحٰبُ النَّارِۘ ', 'Demikianlah (sebagaimana berlaku kepada umat terdahulu), ketetapan Tuhanmu itu berlaku pula bagi orang-orang yang kufur bahwa mereka adalah para penghuni neraka.', '', 'https://everyayah.com/data/Alafasy_128kbps/040006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:7', 40, 7, 24, 467, 4140, 'اَلَّذِيْنَ يَحْمِلُوْنَ الْعَرْشَ وَمَنْ حَوْلَهٗ يُسَبِّحُوْنَ بِحَمْدِ رَبِّهِمْ وَيُؤْمِنُوْنَ بِهٖ وَيَسْتَغْفِرُوْنَ لِلَّذِيْنَ اٰمَنُوْاۚ رَبَّنَا وَسِعْتَ كُلَّ شَيْءٍ رَّحْمَةً وَّعِلْمًا فَاغْفِرْ لِلَّذِيْنَ تَابُوْا وَاتَّبَعُوْا سَبِيْلَكَ وَقِهِمْ عَذَابَ الْجَحِيْمِ ', '(Para malaikat) yang memikul ʻArasy dan yang berada di sekelilingnya selalu bertasbih dengan memuji Tuhannya, beriman kepada-Nya, dan memohonkan ampunan untuk orang-orang yang beriman. (Mereka berkata,) “Wahai Tuhan kami, rahmat dan ilmu-Mu meliputi segala sesuatu. Maka, berikanlah ampunan kepada orang-orang yang bertobat serta mengikuti jalan-Mu dan lindungilah mereka dari azab (neraka) Jahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/040007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:8', 40, 8, 24, 468, 4141, 'رَبَّنَا وَاَدْخِلْهُمْ جَنّٰتِ عَدْنِ ِۨالَّتِيْ وَعَدْتَّهُمْ وَمَنْ صَلَحَ مِنْ اٰبَاۤىِٕهِمْ وَاَزْوَاجِهِمْ وَذُرِّيّٰتِهِمْ ۗاِنَّكَ اَنْتَ الْعَزِيْزُ الْحَكِيْمُۙ ', 'Wahai Tuhan kami, masukkanlah mereka ke dalam surga ‘Adn yang telah Engkau janjikan kepada mereka serta orang yang saleh di antara nenek moyang, istri, dan keturunan mereka. Sesungguhnya Engkaulah Yang Maha Perkasa lagi Maha Bijaksana.', '', 'https://everyayah.com/data/Alafasy_128kbps/040008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:9', 40, 9, 24, 468, 4142, 'وَقِهِمُ السَّيِّاٰتِۗ وَمَنْ تَقِ السَّيِّاٰتِ يَوْمَىِٕذٍ فَقَدْ رَحِمْتَهٗ ۗوَذٰلِكَ هُوَ الْفَوْزُ الْعَظِيْمُ ࣖ ', 'Lindungilah mereka dari keburukan. Siapa yang Engkau lindungi dari keburukan pada hari itu, sungguh, Engkau telah menganugerahkan rahmat kepadanya. Itulah kemenangan yang agung.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:10', 40, 10, 24, 468, 4143, 'اِنَّ الَّذِيْنَ كَفَرُوْا يُنَادَوْنَ لَمَقْتُ اللّٰهِ اَكْبَرُ مِنْ مَّقْتِكُمْ اَنْفُسَكُمْ اِذْ تُدْعَوْنَ اِلَى الْاِيْمَانِ فَتَكْفُرُوْنَ', 'Sesungguhnya orang-orang yang kufur akan diseru (oleh malaikat pada hari Kiamat), “Sungguh, kebencian Allah (kepadamu) jauh lebih besar daripada kebencianmu kepada dirimu sendiri ketika kamu diseru untuk beriman, lalu kamu mengingkarinya.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:11', 40, 11, 24, 468, 4144, 'قَالُوْا رَبَّنَآ اَمَتَّنَا اثْنَتَيْنِ وَاَحْيَيْتَنَا اثْنَتَيْنِ فَاعْتَرَفْنَا بِذُنُوْبِنَا فَهَلْ اِلٰى خُرُوْجٍ مِّنْ سَبِيْلٍ', 'Mereka menjawab, “Wahai Tuhan kami, Engkau telah mematikan kami dua kali dan telah menghidupkan kami dua kali (pula), lalu kami mengakui dosa-dosa kami. Maka, adakah jalan (bagi kami) untuk keluar (dari neraka)?”', '', 'https://everyayah.com/data/Alafasy_128kbps/040011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:12', 40, 12, 24, 468, 4145, 'ذٰلِكُمْ بِاَنَّهٗٓ اِذَا دُعِيَ اللّٰهُ وَحْدَهٗ كَفَرْتُمْۚ وَاِنْ يُّشْرَكْ بِهٖ تُؤْمِنُوْا ۗفَالْحُكْمُ لِلّٰهِ الْعَلِيِّ الْكَبِيْرِ', '(Dikatakan kepada mereka,) “Itu (terjadi) karena kamu benar-benar kufur apabila diseru untuk menyembah Allah semata. (Namun,) jika Dia dipersekutukan, kamu (langsung) percaya. Maka, keputusan (saat ini) ada pada Allah Yang Maha Tinggi lagi Maha Besar.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:13', 40, 13, 24, 468, 4146, 'هُوَ الَّذِيْ يُرِيْكُمْ اٰيٰتِهٖ وَيُنَزِّلُ لَكُمْ مِّنَ السَّمَاۤءِ رِزْقًا ۗوَمَا يَتَذَكَّرُ اِلَّا مَنْ يُّنِيْبُ', 'Dialah yang memperlihatkan tanda-tanda (kekuasaan)-Nya kepadamu dan menurunkan rezeki dari langit untukmu. Yang mendapat pelajaran tidak lain, kecuali orang-orang yang kembali (kepada Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/040013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:14', 40, 14, 24, 468, 4147, 'فَادْعُوا اللّٰهَ مُخْلِصِيْنَ لَهُ الدِّيْنَ وَلَوْ كَرِهَ الْكٰفِرُوْنَ', 'Maka, sembahlah Allah dengan mengikhlaskan ketaatan kepada-Nya meskipun orang-orang kafir tidak menyukai(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/040014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:15', 40, 15, 24, 468, 4148, 'رَفِيْعُ الدَّرَجٰتِ ذُو الْعَرْشِۚ يُلْقِى الرُّوْحَ مِنْ اَمْرِهٖ عَلٰى مَنْ يَّشَاۤءُ مِنْ عِبَادِهٖ لِيُنْذِرَ يَوْمَ التَّلَاقِۙ', '(Dialah) Yang Maha Tinggi derajat-Nya, yang memiliki ʻArasy, yang menurunkan wahyu dengan perintah-Nya kepada siapa yang Dia kehendaki di antara hamba-hamba-Nya agar memperingatkan (manusia) tentang hari pertemuan (hari Kiamat).', '', 'https://everyayah.com/data/Alafasy_128kbps/040015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:16', 40, 16, 24, 468, 4149, 'يَوْمَ هُمْ بٰرِزُوْنَ ۚ لَا يَخْفٰى عَلَى اللّٰهِ مِنْهُمْ شَيْءٌ ۗلِمَنِ الْمُلْكُ الْيَوْمَ ۗ لِلّٰهِ الْوَاحِدِ الْقَهَّارِ', '(Yaitu) pada hari (ketika) mereka tampak dengan jelas (di hadapan Tuhan-Nya), tidak (ada) satu (keadaan) pun dari mereka yang tersembunyi di sisi Allah. (Allah berfirman,) “Milik siapakah kerajaan pada hari ini?” (Lalu, dijawab,) “Milik Allah Yang Maha Esa lagi Maha Mengalahkan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:17', 40, 17, 24, 469, 4150, 'اَلْيَوْمَ تُجْزٰى كُلُّ نَفْسٍۢ بِمَا كَسَبَتْ ۗ لَا ظُلْمَ الْيَوْمَ ۗاِنَّ اللّٰهَ سَرِيْعُ الْحِسَابِ', 'Pada hari ini setiap jiwa diberi balasan sesuai dengan apa yang telah diusahakannya. Tidak ada yang terzalimi pada hari ini. Sesungguhnya Allah sangat cepat perhitungan-Nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/040017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:18', 40, 18, 24, 469, 4151, 'وَاَنْذِرْهُمْ يَوْمَ الْاٰزِفَةِ اِذِ الْقُلُوْبُ لَدَى الْحَنَاجِرِ كٰظِمِيْنَ ەۗ مَا لِلظّٰلِمِيْنَ مِنْ حَمِيْمٍ وَّلَا شَفِيْعٍ يُّطَاعُۗ', 'Berilah mereka peringatan akan hari yang makin dekat (hari Kiamat, yaitu) ketika hati (menyesak) sampai di kerongkongan karena menahan (kesedihan). Tidak ada seorang pun teman setia bagi orang yang zalim dan tidak ada baginya seorang penolong yang diterima (pertolongannya).', '', 'https://everyayah.com/data/Alafasy_128kbps/040018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:19', 40, 19, 24, 469, 4152, 'يَعْلَمُ خَاۤىِٕنَةَ الْاَعْيُنِ وَمَا تُخْفِى الصُّدُوْرُ', 'Dia mengetahui (pandangan) mata yang khianat665) dan apa yang tersembunyi di dalam dada.', '665) Maksud ungkapan pandangan yang khianat adalah pandangan pada hal-hal yang terlarang, seperti memandang lawan jenis yang bukan mahram tanpa alasan yang dibenarkan syariat.', 'https://everyayah.com/data/Alafasy_128kbps/040019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:20', 40, 20, 24, 469, 4153, 'وَاللّٰهُ يَقْضِيْ بِالْحَقِّ ۗوَالَّذِيْنَ يَدْعُوْنَ مِنْ دُوْنِهٖ لَا يَقْضُوْنَ بِشَيْءٍ ۗاِنَّ اللّٰهَ هُوَ السَّمِيْعُ الْبَصِيْرُ ࣖ', 'Allah memutuskan dengan hak (benar dan adil), sedangkan mereka yang disembah selain-Nya tidak mampu memutuskan dengan suatu apa pun. Sesungguhnya Allah, Dialah Yang Maha Mendengar lagi Maha Melihat.', '', 'https://everyayah.com/data/Alafasy_128kbps/040020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:21', 40, 21, 24, 469, 4154, '۞ اَوَلَمْ يَسِيْرُوْا فِى الْاَرْضِ فَيَنْظُرُوْا كَيْفَ كَانَ عَاقِبَةُ الَّذِيْنَ كَانُوْا مِنْ قَبْلِهِمْ ۗ كَانُوْا هُمْ اَشَدَّ مِنْهُمْ قُوَّةً وَّاٰثَارًا فِى الْاَرْضِ فَاَخَذَهُمُ اللّٰهُ بِذُنُوْبِهِمْ ۗوَمَا كَانَ لَهُمْ مِّنَ اللّٰهِ مِنْ وَّاقٍ', 'Apakah mereka tidak berjalan di bumi, lalu memperhatikan bagaimana kesudahan orang-orang yang sebelum mereka? Orang-orang itu lebih hebat kekuatannya daripada mereka dan (lebih banyak) peninggalan (peradaban)-nya di bumi. Akan tetapi, Allah mengazab mereka karena dosa-dosanya. Tidak ada suatu pun yang melindungi mereka dari (azab) Allah.', '', 'https://everyayah.com/data/Alafasy_128kbps/040021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:22', 40, 22, 24, 469, 4155, 'ذٰلِكَ بِاَنَّهُمْ كَانَتْ تَّأْتِيْهِمْ رُسُلُهُمْ بِالْبَيِّنٰتِ فَكَفَرُوْا فَاَخَذَهُمُ اللّٰهُ ۗاِنَّهٗ قَوِيٌّ شَدِيْدُ الْعِقَابِ', 'Yang demikian itu adalah karena sesungguhnya rasul-rasul telah datang kepada mereka dengan membawa bukti-bukti yang nyata666) lalu mereka ingkar. Maka, Allah mengazab mereka. Sesungguhnya Dia Maha Kuat lagi Maha Keras hukuman-Nya.', '666) Maksud bukti-bukti yang nyata adalah mukjizat, hukum-hukum, dan ajaran yang dibawanya.', 'https://everyayah.com/data/Alafasy_128kbps/040022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:23', 40, 23, 24, 469, 4156, 'وَلَقَدْ اَرْسَلْنَا مُوْسٰى بِاٰيٰتِنَا وَسُلْطٰنٍ مُّبِيْنٍۙ', 'Sungguh, Kami benar-benar telah mengutus Musa dengan (membawa) ayat-ayat Kami dan keterangan yang nyata', '', 'https://everyayah.com/data/Alafasy_128kbps/040023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:24', 40, 24, 24, 469, 4157, 'اِلٰى فِرْعَوْنَ وَهَامٰنَ وَقَارُوْنَ فَقَالُوْا سٰحِرٌ كَذَّابٌ', 'kepada Fir‘aun, Haman, dan Qarun. Lalu, mereka berkata, “(Musa) itu seorang penyihir lagi pendusta.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:25', 40, 25, 24, 469, 4158, 'فَلَمَّا جَاۤءَهُمْ بِالْحَقِّ مِنْ عِنْدِنَا قَالُوا اقْتُلُوْٓا اَبْنَاۤءَ الَّذِيْنَ اٰمَنُوْا مَعَهٗ وَاسْتَحْيُوْا نِسَاۤءَهُمْ ۗوَمَا كَيْدُ الْكٰفِرِيْنَ اِلَّا فِيْ ضَلٰلٍ', 'Ketika dia (Musa) datang kepada mereka membawa kebenaran dari Kami, mereka berkata, “Bunuhlah anak laki-laki orang-orang yang beriman bersama dia dan biarkan hidup perempuan-perempuan mereka.” Tidaklah tipu daya orang-orang kafir itu kecuali sia-sia belaka.', '', 'https://everyayah.com/data/Alafasy_128kbps/040025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:26', 40, 26, 24, 470, 4159, 'وَقَالَ فِرْعَوْنُ ذَرُوْنِيْٓ اَقْتُلْ مُوْسٰى وَلْيَدْعُ رَبَّهٗ ۚاِنِّيْٓ اَخَافُ اَنْ يُّبَدِّلَ دِيْنَكُمْ اَوْ اَنْ يُّظْهِرَ فِى الْاَرْضِ الْفَسَادَ', 'Fir‘aun berkata (kepada pembesar-pembesarnya), “Biar aku yang membunuh Musa dan suruh dia memohon kepada Tuhannya. Sesungguhnya aku khawatir (bahwa) dia akan menukar agamamu atau menimbulkan kerusakan di bumi.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:27', 40, 27, 24, 470, 4160, 'وَقَالَ مُوْسٰىٓ اِنِّيْ عُذْتُ بِرَبِّيْ وَرَبِّكُمْ مِّنْ كُلِّ مُتَكَبِّرٍ لَّا يُؤْمِنُ بِيَوْمِ الْحِسَابِ ࣖ ', 'Musa berkata, “Sesungguhnya aku berlindung kepada Tuhanku dan Tuhanmu dari setiap orang yang menyombongkan diri yang tidak beriman kepada hari Perhitungan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:28', 40, 28, 24, 470, 4161, 'وَقَالَ رَجُلٌ مُّؤْمِنٌۖ مِّنْ اٰلِ فِرْعَوْنَ يَكْتُمُ اِيْمَانَهٗٓ اَتَقْتُلُوْنَ رَجُلًا اَنْ يَّقُوْلَ رَبِّيَ اللّٰهُ وَقَدْ جَاۤءَكُمْ بِالْبَيِّنٰتِ مِنْ رَّبِّكُمْ ۗوَاِنْ يَّكُ كَاذِبًا فَعَلَيْهِ كَذِبُهٗ ۚوَاِنْ يَّكُ صَادِقًا يُّصِبْكُمْ بَعْضُ الَّذِيْ يَعِدُكُمْ ۗاِنَّ اللّٰهَ لَا يَهْدِيْ مَنْ هُوَ مُسْرِفٌ كَذَّابٌ', 'Seorang laki-laki mukmin dari keluarga Fir‘aun yang menyembunyikan imannya berkata, “Apakah kamu akan membunuh seseorang karena dia berkata, ‘Tuhanku adalah Allah.’ Padahal, sungguh dia telah datang kepadamu dengan membawa bukti-bukti yang nyata dari Tuhanmu. Jika dia seorang pendusta, dialah yang akan menanggung (dosa) dustanya itu, dan jika dia seorang yang benar, niscaya sebagian (bencana) yang diancamkan kepadamu akan menimpamu. Sesungguhnya Allah tidak memberi petunjuk kepada orang yang melampaui batas lagi pendusta.', '', 'https://everyayah.com/data/Alafasy_128kbps/040028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:29', 40, 29, 24, 470, 4162, 'يٰقَوْمِ لَكُمُ الْمُلْكُ الْيَوْمَ ظٰهِرِيْنَ فِى الْاَرْضِۖ فَمَنْ يَّنْصُرُنَا مِنْۢ بَأْسِ اللّٰهِ اِنْ جَاۤءَنَا ۗقَالَ فِرْعَوْنُ مَآ اُرِيْكُمْ اِلَّا مَآ اَرٰى وَمَآ اَهْدِيْكُمْ اِلَّا سَبِيْلَ الرَّشَادِ', 'Wahai kaumku, pada hari ini kerajaan ada padamu dengan berkuasa di bumi. Akan tetapi, siapa yang akan menolong kita dari azab Allah jika (azab itu) menimpa kita?” Fir‘aun berkata, “Aku hanya mengemukakan kepadamu apa yang aku pandang baik dan aku hanya menunjukkan kepadamu jalan yang benar.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:30', 40, 30, 24, 470, 4163, 'وَقَالَ الَّذِيْٓ اٰمَنَ يٰقَوْمِ اِنِّيْٓ اَخَافُ عَلَيْكُمْ مِّثْلَ يَوْمِ الْاَحْزَابِۙ  ', 'Orang yang beriman itu berkata, “Wahai kaumku, sesungguhnya aku khawatir (bahwa) kamu akan ditimpa (bencana) seperti hari (kehancuran) golongan yang bersekutu.', '', 'https://everyayah.com/data/Alafasy_128kbps/040030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:31', 40, 31, 24, 470, 4164, 'مِثْلَ دَأْبِ قَوْمِ نُوْحٍ وَّعَادٍ وَّثَمُوْدَ وَالَّذِيْنَ مِنْۢ بَعْدِهِمْ ۗوَمَا اللّٰهُ يُرِيْدُ ظُلْمًا لِّلْعِبَادِ', '(Yakni) seperti kebiasaan kaum Nuh, ‘Ad, Samud, dan orang-orang yang datang setelah mereka (yang ditimpa bencana). Allah tidak menghendaki kezaliman terhadap hamba-hamba-Nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/040031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:32', 40, 32, 24, 470, 4165, 'وَيٰقَوْمِ اِنِّيْٓ اَخَافُ عَلَيْكُمْ يَوْمَ التَّنَادِۙ  ', 'Wahai kaumku, sesungguhnya aku khawatir terhadapmu akan (siksaan) hari saling memanggil.667)', '667) Hari Kiamat disebut hari saling memanggil karena orang yang berkumpul di Padang Mahsyar saling memanggil untuk meminta tolong.', 'https://everyayah.com/data/Alafasy_128kbps/040032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:33', 40, 33, 24, 470, 4166, 'يَوْمَ تُوَلُّوْنَ مُدْبِرِيْنَۚ مَا لَكُمْ مِّنَ اللّٰهِ مِنْ عَاصِمٍۚ وَمَنْ يُّضْلِلِ اللّٰهُ فَمَا لَهٗ مِنْ هَادٍ', '(Yaitu) pada hari (ketika) kamu dipalingkan dengan berbalik ke belakang (mencari perlindungan). Tidak ada seorang pun yang mampu menyelamatkanmu dari (azab) Allah. Siapa yang disesatkan oleh Allah tidak ada baginya (seorang) pemberi petunjuk pun.', '', 'https://everyayah.com/data/Alafasy_128kbps/040033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:34', 40, 34, 24, 471, 4167, 'وَلَقَدْ جَاۤءَكُمْ يُوْسُفُ مِنْ قَبْلُ بِالْبَيِّنٰتِ فَمَا زِلْتُمْ فِيْ شَكٍّ مِّمَّا جَاۤءَكُمْ بِهٖ ۗحَتّٰىٓ اِذَا هَلَكَ قُلْتُمْ لَنْ يَّبْعَثَ اللّٰهُ مِنْۢ بَعْدِهٖ رَسُوْلًا ۗ كَذٰلِكَ يُضِلُّ اللّٰهُ مَنْ هُوَ مُسْرِفٌ مُّرْتَابٌۙ', 'Sungguh, sebelum itu Yusuf benar-benar telah datang kepadamu dengan membawa bukti-bukti yang nyata. Akan tetapi, kamu senantiasa dalam keraguan terhadap apa yang dibawanya hingga ketika dia wafat, kamu berkata, ‘Allah sekali-kali tidak akan mengirim seorang rasul pun setelahnya.’ Demikianlah Allah membiarkan sesat orang yang melampaui batas dan ragu-ragu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:35', 40, 35, 24, 471, 4168, ' ۨالَّذِيْنَ يُجَادِلُوْنَ فِيْٓ اٰيٰتِ اللّٰهِ بِغَيْرِ سُلْطٰنٍ اَتٰىهُمْۗ  كَبُرَ مَقْتًا عِنْدَ اللّٰهِ وَعِنْدَ الَّذِيْنَ اٰمَنُوْا ۗ كَذٰلِكَ يَطْبَعُ اللّٰهُ عَلٰى كُلِّ قَلْبِ مُتَكَبِّرٍ جَبَّارٍ', 'Orang-orang yang memperdebatkan ayat-ayat Allah tanpa alasan yang sampai kepada mereka, sangat besar kemurkaan (bagi mereka) di sisi Allah dan di sisi orang-orang yang beriman. Demikianlah Allah mengunci hati setiap orang yang sombong lagi sewenang-wenang.', '', 'https://everyayah.com/data/Alafasy_128kbps/040035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:36', 40, 36, 24, 471, 4169, 'وَقَالَ فِرْعَوْنُ يٰهَامٰنُ ابْنِ لِيْ صَرْحًا لَّعَلِّيْٓ اَبْلُغُ الْاَسْبَابَۙ', 'Fir‘aun berkata, “Hai Haman, buatkanlah untukku sebuah bangunan yang tinggi agar aku sampai ke pintu-pintu,', '', 'https://everyayah.com/data/Alafasy_128kbps/040036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:37', 40, 37, 24, 471, 4170, 'اَسْبَابَ السَّمٰوٰتِ فَاَطَّلِعَ اِلٰٓى اِلٰهِ مُوْسٰى وَاِنِّيْ لَاَظُنُّهٗ كَاذِبًا ۗوَكَذٰلِكَ زُيِّنَ لِفِرْعَوْنَ سُوْۤءُ عَمَلِهٖ وَصُدَّ عَنِ السَّبِيْلِ ۗوَمَا كَيْدُ فِرْعَوْنَ اِلَّا فِيْ تَبَابٍ ࣖ ', '(yaitu) pintu-pintu langit, agar aku dapat melihat Tuhannya Musa. Sesungguhnya aku benar-benar meyakininya sebagai seorang pendusta.” Demikianlah dijadikan terasa indah bagi Fir‘aun perbuatan buruknya itu, dan dia tertutup dari jalan (yang benar). Tipu daya Fir‘aun itu tidak lain kecuali membawa kerugian.', '', 'https://everyayah.com/data/Alafasy_128kbps/040037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:38', 40, 38, 24, 471, 4171, 'وَقَالَ الَّذِيْٓ اٰمَنَ يٰقَوْمِ اتَّبِعُوْنِ اَهْدِكُمْ سَبِيْلَ الرَّشَادِۚ', 'Orang yang beriman itu berkata, “Wahai kaumku, ikutilah aku! Aku akan menunjukkan kepadamu jalan yang benar.', '', 'https://everyayah.com/data/Alafasy_128kbps/040038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:39', 40, 39, 24, 471, 4172, 'يٰقَوْمِ اِنَّمَا هٰذِهِ الْحَيٰوةُ الدُّنْيَا مَتَاعٌ  ۖوَّاِنَّ الْاٰخِرَةَ هِيَ دَارُ الْقَرَارِ', 'Wahai kaumku, sesungguhnya kehidupan dunia ini hanyalah kesenangan (sementara) dan sesungguhnya akhirat itulah negeri yang kekal.', '', 'https://everyayah.com/data/Alafasy_128kbps/040039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:40', 40, 40, 24, 471, 4173, 'مَنْ عَمِلَ سَيِّئَةً فَلَا يُجْزٰىٓ اِلَّا مِثْلَهَاۚ وَمَنْ عَمِلَ صَالِحًا مِّنْ ذَكَرٍ اَوْ اُنْثٰى وَهُوَ مُؤْمِنٌ فَاُولٰۤىِٕكَ يَدْخُلُوْنَ الْجَنَّةَ يُرْزَقُوْنَ فِيْهَا بِغَيْرِ حِسَابٍ ', 'Siapa yang mengerjakan keburukan tidak dibalas, kecuali sebanding dengan keburukan itu. Siapa yang mengerjakan kebajikan, baik laki-laki maupun perempuan sedangkan dia dalam keadaan beriman, akan masuk surga. Mereka dianugerahi rezeki di dalamnya tanpa perhitungan.', '', 'https://everyayah.com/data/Alafasy_128kbps/040040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:41', 40, 41, 24, 472, 4174, '۞ وَيٰقَوْمِ مَا لِيْٓ اَدْعُوْكُمْ اِلَى النَّجٰوةِ وَتَدْعُوْنَنِيْٓ اِلَى النَّارِۗ', 'Wahai kaumku, bagaimanakah ini? Aku menyerumu kepada keselamatan, sedangkan kamu menyeruku kepada neraka.', '', 'https://everyayah.com/data/Alafasy_128kbps/040041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:42', 40, 42, 24, 472, 4175, 'تَدْعُوْنَنِيْ لِاَكْفُرَ بِاللّٰهِ وَاُشْرِكَ بِهٖ مَا لَيْسَ لِيْ بِهٖ عِلْمٌ وَّاَنَا۠ اَدْعُوْكُمْ اِلَى الْعَزِيْزِ الْغَفَّارِ', 'Kamu menyeruku agar kufur kepada Allah dan mempersekutukan-Nya dengan sesuatu yang tidak ada padaku pengetahuan tentangnya, padahal aku menyerumu (beriman) kepada Yang Maha Perkasa lagi Maha Pengampun.', '', 'https://everyayah.com/data/Alafasy_128kbps/040042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:43', 40, 43, 24, 472, 4176, 'لَا جَرَمَ اَنَّمَا تَدْعُوْنَنِيْٓ اِلَيْهِ لَيْسَ لَهٗ دَعْوَةٌ فِى الدُّنْيَا وَلَا فِى الْاٰخِرَةِ وَاَنَّ مَرَدَّنَآ اِلَى اللّٰهِ وَاَنَّ الْمُسْرِفِيْنَ هُمْ اَصْحٰبُ النَّارِ', 'Sudah pasti bahwa apa yang kamu serukan kepadaku (agar menyembah)-nya bukanlah seruan yang layak sama sekali di dunia dan di akhirat. Sesungguhnya tempat kembali kita pasti kepada Allah dan sesungguhnya orang-orang yang melampaui batas akan menjadi penghuni neraka.', '', 'https://everyayah.com/data/Alafasy_128kbps/040043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:44', 40, 44, 24, 472, 4177, 'فَسَتَذْكُرُوْنَ مَآ اَقُوْلُ لَكُمْۗ وَاُفَوِّضُ اَمْرِيْٓ اِلَى اللّٰهِ ۗاِنَّ اللّٰهَ بَصِيْرٌ ۢبِالْعِبَادِ', 'Kelak kamu akan mengingat apa yang kukatakan kepadamu. Aku menyerahkan urusanku kepada Allah. Sesungguhnya Allah Maha Melihat hamba-hamba-Nya.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:45', 40, 45, 24, 472, 4178, 'فَوَقٰىهُ اللّٰهُ سَيِّاٰتِ مَا مَكَرُوْا وَحَاقَ بِاٰلِ فِرْعَوْنَ سُوْۤءُ الْعَذَابِۚ', 'Maka, Allah melindunginya (orang yang beriman) dari berbagai kejahatan tipu daya mereka, sedangkan Fir‘aun beserta kaumnya dikepung oleh seburuk-buruk azab.', '', 'https://everyayah.com/data/Alafasy_128kbps/040045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:46', 40, 46, 24, 472, 4179, 'اَلنَّارُ يُعْرَضُوْنَ عَلَيْهَا غُدُوًّا وَّعَشِيًّا ۚوَيَوْمَ تَقُوْمُ السَّاعَةُ ۗ اَدْخِلُوْٓا اٰلَ فِرْعَوْنَ اَشَدَّ الْعَذَابِ', 'Neraka diperlihatkan kepada mereka (di alam barzakh) pada pagi dan petang. Pada hari terjadinya kiamat, (dikatakan,) “Masukkanlah Fir‘aun dan kaumnya ke dalam sekeras-keras azab!”', '', 'https://everyayah.com/data/Alafasy_128kbps/040046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:47', 40, 47, 24, 472, 4180, 'وَاِذْ يَتَحَاۤجُّوْنَ فِى النَّارِ فَيَقُوْلُ الضُّعَفٰۤؤُا لِلَّذِيْنَ اسْتَكْبَرُوْٓا اِنَّا كُنَّا لَكُمْ تَبَعًا فَهَلْ اَنْتُمْ مُّغْنُوْنَ عَنَّا نَصِيْبًا مِّنَ النَّارِ', '(Ingatlah) ketika mereka berbantah-bantahan di dalam neraka. Orang yang lemah berkata kepada orang-orang yang menyombongkan diri, “Sesungguhnya kami (dahulu) adalah pengikut-pengikutmu, maka dapatkah kamu melepaskan sebagian (azab) api neraka yang menimpa kami?”', '', 'https://everyayah.com/data/Alafasy_128kbps/040047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:48', 40, 48, 24, 472, 4181, 'قَالَ الَّذِيْنَ اسْتَكْبَرُوْٓا اِنَّا كُلٌّ فِيْهَآ اِنَّ اللّٰهَ قَدْ حَكَمَ بَيْنَ الْعِبَادِ', 'Orang-orang yang menyombongkan diri menjawab, “Sesungguhnya kita semua sama-sama di dalamnya (neraka). Sesungguhnya Allah telah menetapkan keputusan di antara hamba-hamba(-Nya).”', '', 'https://everyayah.com/data/Alafasy_128kbps/040048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:49', 40, 49, 24, 472, 4182, 'وَقَالَ الَّذِيْنَ فِى النَّارِ لِخَزَنَةِ جَهَنَّمَ ادْعُوْا رَبَّكُمْ يُخَفِّفْ عَنَّا يَوْمًا مِّنَ الْعَذَابِ ', 'Orang-orang yang berada di dalam neraka berkata kepada penjaga-penjaga (neraka) Jahanam, “Mohonkanlah kepada Tuhanmu agar Dia meringankan azab atas kami sehari saja.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:50', 40, 50, 24, 473, 4183, 'قَالُوْٓا اَوَلَمْ تَكُ تَأْتِيْكُمْ رُسُلُكُمْ بِالْبَيِّنٰتِ ۗقَالُوْا بَلٰىۗ قَالُوْا فَادْعُوْا ۚوَمَا دُعٰۤؤُا الْكٰفِرِيْنَ اِلَّا فِيْ ضَلٰلٍ ࣖ', '(Penjaga-penjaga Jahanam) berkata, “Bukankah rasul-rasul telah datang kepadamu dengan membawa bukti-bukti yang nyata?” Mereka menjawab, “Benar (telah datang).” Mereka berkata, “Mohonlah (sendiri!)” (Akan tetapi,) doa orang-orang kafir itu sia-sia belaka.', '', 'https://everyayah.com/data/Alafasy_128kbps/040050.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:51', 40, 51, 24, 473, 4184, 'اِنَّا لَنَنْصُرُ رُسُلَنَا وَالَّذِيْنَ اٰمَنُوْا فِى الْحَيٰوةِ الدُّنْيَا وَيَوْمَ يَقُوْمُ الْاَشْهَادُۙ ', 'Sesungguhnya Kami akan menolong rasul-rasul Kami dan orang-orang yang beriman dalam kehidupan dunia dan pada hari dihadirkannya para saksi (hari Kiamat),', '', 'https://everyayah.com/data/Alafasy_128kbps/040051.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:52', 40, 52, 24, 473, 4185, 'يَوْمَ لَا يَنْفَعُ الظّٰلِمِيْنَ مَعْذِرَتُهُمْ وَلَهُمُ اللَّعْنَةُ وَلَهُمْ سُوْۤءُ الدَّارِ ', '(yaitu) hari (ketika) permintaan maaf tidak berguna bagi orang-orang zalim. Bagi mereka laknat dan tempat tinggal yang buruk.', '', 'https://everyayah.com/data/Alafasy_128kbps/040052.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:53', 40, 53, 24, 473, 4186, 'وَلَقَدْاٰتَيْنَا مُوْسَى الْهُدٰى وَاَوْرَثْنَا بَنِيْٓ اِسْرَاۤءِيْلَ الْكِتٰبَۙ ', 'Sungguh, Kami benar-benar telah menganugerahkan petunjuk kepada Musa dan mewariskan Kitab (Taurat) kepada Bani Israil', '', 'https://everyayah.com/data/Alafasy_128kbps/040053.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:54', 40, 54, 24, 473, 4187, 'هُدًى وَّذِكْرٰى لِاُولِى الْاَلْبَابِ', 'untuk menjadi petunjuk dan peringatan bagi orang-orang yang berpikiran sehat.', '', 'https://everyayah.com/data/Alafasy_128kbps/040054.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:55', 40, 55, 24, 473, 4188, 'فَاصْبِرْ اِنَّ وَعْدَ اللّٰهِ حَقٌّ وَّاسْتَغْفِرْ لِذَنْۢبِكَ وَسَبِّحْ بِحَمْدِ رَبِّكَ بِالْعَشِيِّ وَالْاِبْكَارِ', 'Bersabarlah, sesungguhnya janji Allah itu benar, mohonlah ampun untuk dosamu, dan bertasbihlah seraya memuji Tuhanmu pada waktu petang dan pagi!', '', 'https://everyayah.com/data/Alafasy_128kbps/040055.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:56', 40, 56, 24, 473, 4189, 'اِنَّ الَّذِيْنَ يُجَادِلُوْنَ فِيْٓ اٰيٰتِ اللّٰهِ بِغَيْرِ سُلْطٰنٍ اَتٰىهُمْ ۙاِنْ فِيْ صُدُوْرِهِمْ اِلَّا كِبْرٌ مَّا هُمْ بِبَالِغِيْهِۚ فَاسْتَعِذْ بِاللّٰهِ ۗاِنَّهٗ هُوَ السَّمِيْعُ الْبَصِيْرُ', 'Sesungguhnya orang-orang yang membantah ayat-ayat Allah tanpa alasan (bukti) yang sampai kepada mereka, tidaklah ada dalam dada mereka kecuali kesombongan (untuk tujuan) yang tidak akan mereka capai, maka mintalah pelindungan kepada Allah. Sesungguhnya Dia Maha Mendengar lagi Maha Melihat.', '', 'https://everyayah.com/data/Alafasy_128kbps/040056.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:57', 40, 57, 24, 473, 4190, 'لَخَلْقُ السَّمٰوٰتِ وَالْاَرْضِ اَكْبَرُ مِنْ خَلْقِ النَّاسِ وَلٰكِنَّ اَكْثَرَ النَّاسِ لَا يَعْلَمُوْنَ', 'Penciptaan langit dan bumi itu sungguh lebih besar daripada penciptaan manusia, tetapi kebanyakan manusia tidak mengetahui.', '', 'https://everyayah.com/data/Alafasy_128kbps/040057.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:58', 40, 58, 24, 473, 4191, 'وَمَا يَسْتَوِى الْاَعْمٰى وَالْبَصِيْرُ ەۙ وَالَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ وَلَا الْمُسِيْۤئُ ۗقَلِيْلًا مَّا تَتَذَكَّرُوْنَ', 'Tidak sama orang buta dengan orang melihat. Tidak (sama) pula orang-orang yang beriman dan mengerjakan kebajikan dengan orang-orang yang berbuat keburukan. Sedikit sekali kamu mengambil pelajaran.', '', 'https://everyayah.com/data/Alafasy_128kbps/040058.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:59', 40, 59, 24, 474, 4192, 'اِنَّ السَّاعَةَ لَاٰتِيَةٌ لَّا رَيْبَ فِيْهَا ۖوَلٰكِنَّ اَكْثَرَ النَّاسِ لَا يُؤْمِنُوْنَ', 'Sesungguhnya hari Kiamat pasti akan datang. Tidak ada keraguan tentangnya, tetapi kebanyakan manusia tidak beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/040059.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:60', 40, 60, 24, 474, 4193, 'وَقَالَ رَبُّكُمُ ادْعُوْنِيْٓ اَسْتَجِبْ لَكُمْ ۗاِنَّ الَّذِيْنَ يَسْتَكْبِرُوْنَ عَنْ عِبَادَتِيْ سَيَدْخُلُوْنَ جَهَنَّمَ دَاخِرِيْنَ ࣖ ', 'Tuhanmu berfirman, “Berdoalah kepada-Ku, niscaya akan Aku perkenankan bagimu (apa yang kamu harapkan). Sesungguhnya orang-orang yang menyombongkan diri tidak mau beribadah kepada-Ku akan masuk (neraka) Jahanam dalam keadaan hina dina.”', '', 'https://everyayah.com/data/Alafasy_128kbps/040060.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('40:61', 40, 61, 24, 474, 4194, 'اَللّٰهُ الَّذِيْ جَعَلَ لَكُمُ الَّيْلَ لِتَسْكُنُوْا فِيْهِ وَالنَّهَارَ مُبْصِرًا ۗاِنَّ اللّٰهَ لَذُوْ فَضْلٍ عَلَى النَّاسِ وَلٰكِنَّ اَكْثَرَ النَّاسِ لَا يَشْكُرُوْنَ', 'Allahlah yang menjadikan malam untukmu agar kamu beristirahat padanya (dan menjadikan) siang terang-benderang (agar kamu bekerja). Sesungguhnya Allah benar-benar memiliki karunia (yang dilimpahkan) kepada manusia, tetapi kebanyakan manusia tidak bersyukur.', '', 'https://everyayah.com/data/Alafasy_128kbps/040061.mp3');
PRAGMA foreign_keys = ON;
